// Extract error details from the failed execution
const errorData = $input.first().json;

// Get execution details
const execution = errorData.execution || {};
const workflow = errorData.workflow || {};
const error = execution.error || {};

// Find the failed node
let failedNode = 'unknown';
let inputSnapshot = null;

if (execution.data?.resultData?.runData) {
  const runData = execution.data.resultData.runData;
  for (const [nodeName, nodeResults] of Object.entries(runData)) {
    const lastResult = nodeResults[nodeResults.length - 1];
    if (lastResult?.error) {
      failedNode = nodeName;
      inputSnapshot = lastResult.inputData?.main?.[0]?.[0]?.json || null;
      break;
    }
  }
}

// Try to extract alert-specific data from the input
let alertId = null;
let ticketNumber = null;
let stationCodes = [];
let emailMessageId = null;

if (inputSnapshot) {
  alertId = inputSnapshot.alert_id || inputSnapshot.alertId || null;
  ticketNumber = inputSnapshot.ticket_number || inputSnapshot.ticketNumber || null;
  stationCodes = inputSnapshot.member_codes || inputSnapshot.stationCodes || [];
  emailMessageId = inputSnapshot.email_message_id || inputSnapshot.emailMessageId || null;
}

// Sanitize input snapshot (remove PII)
function sanitize(obj) {
  if (!obj) return null;
  const sanitized = { ...obj };
  const piiFields = ['customer_email', 'customer_phone', 'customer_first_name', 'customer_last_name', 'original_body'];
  for (const field of piiFields) {
    if (sanitized[field]) {
      sanitized[field] = '[REDACTED]';
    }
  }
  return sanitized;
}

const now = new Date().toISOString();

return [{
  json: {
    alert_id: alertId,
    ticket_number: ticketNumber,
    station_codes: JSON.stringify(stationCodes),
    error_type: error.name || 'UnknownError',
    error_message: error.message || 'No error message available',
    error_details: JSON.stringify({
      stack: error.stack?.substring(0, 500),
      timestamp: error.timestamp,
      workflow_id: workflow.id,
      workflow_name: workflow.name,
      execution_id: execution.id
    }),
    failed_node: failedNode,
    input_snapshot: JSON.stringify(sanitize(inputSnapshot)),
    email_message_id: emailMessageId,
    reviewed: false,
    created_at: now
  }
}];

// Prepare notification email (no PII)
const data = $input.first().json;

const subject = `DPS Dead Letter: ${data.error_type} in ${data.failed_node}`;

const body = `A DPS workflow execution failed and has been logged to the dead letter queue.

=== Error Summary ===
Error Type: ${data.error_type}
Failed Node: ${data.failed_node}
Time: ${data.created_at}

=== Context (if available) ===
Alert ID: ${data.alert_id || 'N/A'}
Ticket Number: ${data.ticket_number || 'N/A'}
Station Codes: ${data.station_codes || '[]'}

=== Error Message ===
${data.error_message}

=== Action Required ===
Please review the dead letter queue in Google Sheets or the database and take appropriate action.

This is an automated notification.`;

return [{
  json: {
    notification_subject: subject,
    notification_body: body
  }
}];
